code = """import json
import pandas as pd

# Load Case data
with open(locals()['var_function-call-9350505817259632488'], 'r') as f:
    cases = json.load(f)
df_cases = pd.DataFrame(cases)

# Load Account data
accounts = locals()['var_function-call-9350505817259633199']
df_accounts = pd.DataFrame(accounts)

# Clean IDs
def clean_id(x):
    if x:
        return x.replace('#', '').strip()
    return x

df_cases['accountid'] = df_cases['accountid'].apply(clean_id)
df_accounts['Id'] = df_accounts['Id'].apply(clean_id)

# Convert dates
df_cases['createddate'] = pd.to_datetime(df_cases['createddate'])
df_cases['closeddate'] = pd.to_datetime(df_cases['closeddate'])

# Define Timeframe: Past 6 quarters relative to 2022-10-26
# "Past 6 quarters" could be interpreted as the last 6 completed quarters (Q2 2021 - Q3 2022)
# or just the last 18 months. 
# Let's assume standard quarters: Q2 2021 (Apr 1) to Q3 2022 (Sep 30).
# If I include Q4 2022 (partial), it's technically current.
# Let's stick to the 18-month window covering the "past 6 quarters".
# Start: 2021-04-01
# End: 2022-09-30 (End of Q3 2022)
start_date = pd.Timestamp('2021-04-01', tz='UTC')
end_date = pd.Timestamp('2022-09-30', tz='UTC')

# Filter cases
mask = (df_cases['closeddate'] >= start_date) & (df_cases['closeddate'] <= end_date)
df_cases_filtered = df_cases[mask].copy()

# Calculate duration (in hours)
df_cases_filtered['duration_hours'] = (df_cases_filtered['closeddate'] - df_cases_filtered['createddate']).dt.total_seconds() / 3600

# Merge with Accounts
df_merged = pd.merge(df_cases_filtered, df_accounts, left_on='accountid', right_on='Id', how='inner')

# Group by State
state_stats = df_merged.groupby('ShippingState')['duration_hours'].mean().reset_index()
state_stats = state_stats.sort_values('duration_hours')

print("__RESULT__:")
print(state_stats.to_json(orient='records'))"""

